    jsonFetch(path, {
      method: 'POST',
      headers: authHeaders,
      body: JSON.stringify(body ?? {}),
    });
  const patch = (path, body) =>
    jsonFetch(path, {
      method: 'PATCH',
      headers: authHeaders,
      body: JSON.stringify(body ?? {}),
    });

  // ---------------------------------------------------------------------------
