//
// This script:
// 1) Logs in as staff and client
// 2) Discovers core IDs (client, warehouse, uom, product, location, outbound/inbound orders)
// 3) Exercises key flows across modules:
//    - Inventory reads
//    - Inbound order create + item add + receive
//    - Outbound order create + item add
//    - Stock reservation create
//    - Adjustment create (no approval apply in this script)
//    - Return order create (RESTOCK) and process (creates RETURN ledger)

const BASE_URL = 'http://localhost:3000';

async function jsonFetch(path, options = {}) {
  const res = await fetch(`${BASE_URL}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(options.headers || {}),
    },
  });
  let text = await res.text();
  let body;
  try {
    body = text ? JSON.parse(text) : null;
  } catch {
    body = text;
  }
  return { status: res.status, body };
}

async function run() {
  console.log('🔍 Running full endpoint test suite...\n');

  // ---------------------------------------------------------------------------
  // 1) Auth logins
  // ---------------------------------------------------------------------------
  console.log('1) Auth logins');

  const staffLogin = await jsonFetch('/auth/staff/login', {
    method: 'POST',
    body: JSON.stringify({
      email: 'admin@emdad3pl.com',
      password: 'password123',
    }),
  });
  console.log('   /auth/staff/login ->', staffLogin.status);
  if (staffLogin.status !== 200 && staffLogin.status !== 201) {
    console.log('   ❌ Staff login failed:', staffLogin.body);
    return;
  }
  const staffToken = staffLogin.body.accessToken;

  const clientLogin = await jsonFetch('/auth/client/login', {
    method: 'POST',
    body: JSON.stringify({
      email: 'client1@acme.com',
      password: 'password123',
    }),
  });
  console.log('   /auth/client/login ->', clientLogin.status);
  let clientPayload = null;
  if (clientLogin.status === 200 || clientLogin.status === 201) {
    console.log('   ✅ Client login OK');
    clientPayload = clientLogin.body.user || null;
  } else {
    console.log('   ⚠️ Client login failed:', clientLogin.body);
  }

  const authHeaders = { Authorization: `Bearer ${staffToken}` };
  console.log();

  // Helper for authenticated GET/POST
  const get = (path) => jsonFetch(path, { method: 'GET', headers: authHeaders });
  const post = (path, body) =>
    jsonFetch(path, {
      method: 'POST',
      headers: authHeaders,
      body: JSON.stringify(body ?? {}),
    });
  const patch = (path, body) =>
    jsonFetch(path, {
      method: 'PATCH',
      headers: authHeaders,
      body: JSON.stringify(body ?? {}),
    });

  // ---------------------------------------------------------------------------
  // 2) Discover core master data (client, warehouse, uom, product, location)
  // ---------------------------------------------------------------------------
  console.log('2) Discovering master data (client, warehouse, uom, product, location)');

  // Clients endpoint (for health check only; clientId comes from JWT payload)
  const clientsRes = await get('/clients');
  console.log('   GET /clients ->', clientsRes.status);
  const clientFromList = Array.isArray(clientsRes.body)
    ? clientsRes.body.find((c) => c.code === 'CLIENT001') || clientsRes.body[0]
    : null;

  const clientId =
    (clientPayload && clientPayload.clientId) ||
    (clientFromList && clientFromList.id) ||
    null;

  if (!clientId) {
    console.log('   ❌ Could not determine clientId (from JWT or /clients).');
    return;
  }

  const warehousesRes = await get('/warehouses');
  console.log('   GET /warehouses ->', warehousesRes.status);
  const warehouse = Array.isArray(warehousesRes.body)
    ? warehousesRes.body.find((w) => w.code === 'WH001') || warehousesRes.body[0]
    : null;
  if (!warehouse) {
    console.log('   ❌ No warehouse found, cannot continue.');
    return;
  }

  const uomRes = await get('/uom');
  console.log('   GET /uom ->', uomRes.status);
  const uomEA = Array.isArray(uomRes.body)
    ? uomRes.body.find((u) => u.code === 'EA') || uomRes.body[0]
    : null;
  if (!uomEA) {
    console.log('   ❌ No UOM found, cannot continue.');
    return;
  }

  const productsRes = await get('/products');
  console.log('   GET /products ->', productsRes.status);
  let product =
    Array.isArray(productsRes.body) && productsRes.body.length
      ? // Prefer a product that belongs to this client
        productsRes.body.find((p) => p.clientId === clientId) ||
        null
      : null;

  // If no suitable product exists, create one for this client
  if (!product) {
    console.log('   No suitable product found; creating test product for client...');
    const sku = `TEST-PROD-${Date.now()}`;
    const createProdRes = await post('/products', {
      clientId,
      sku,
      name: 'Test Product (auto-created by test-all-endpoints)',
      defaultUomId: uomEA.id,
      minThreshold: 0,
      isActive: true,
    });
    console.log('   POST /products ->', createProdRes.status);
    if (createProdRes.status !== 201 && createProdRes.status !== 200) {
      console.log('   ❌ Failed to create test product:', createProdRes.body);
      return;
    }
    product = createProdRes.body;
  }

  const locationsRes = await get('/warehouses/' + warehouse.id + '/locations');
  console.log('   GET /warehouses/:id/locations ->', locationsRes.status);
  const location =
    Array.isArray(locationsRes.body) && locationsRes.body.length > 0
      ? locationsRes.body[0]
      : null;

  console.log('   Using:');
  console.log(
    '     clientId   =',
    clientId,
    clientFromList ? clientFromList.code : '(from JWT)',
  );
  console.log('     warehouseId=', warehouse.id, warehouse.code);
  console.log('     uomId      =', uomEA.id, uomEA.code);
  console.log('     productId  =', product.id, product.sku);
  if (location) console.log('     locationId =', location.id, location.code);
  console.log();

  // ---------------------------------------------------------------------------
  // 3) Inventory reads
  // ---------------------------------------------------------------------------
  console.log('3) Inventory reads');

  const currentStockRes = await get('/inventory/current-stock');
  console.log('   GET /inventory/current-stock ->', currentStockRes.status);
  if (currentStockRes.status === 200) {
    console.log(
      '   Count:',
      Array.isArray(currentStockRes.body) ? currentStockRes.body.length : 'n/a',
    );
  }

  const ledgerRes = await get('/inventory/ledger');
  console.log('   GET /inventory/ledger ->', ledgerRes.status);
  if (ledgerRes.status === 200) {
    console.log(
      '   Count:',
      Array.isArray(ledgerRes.body) ? ledgerRes.body.length : 'n/a',
    );
  }
  console.log();

  // ---------------------------------------------------------------------------
  // 4) Inbound order flow (create -> add item -> receive)
  // ---------------------------------------------------------------------------
  console.log('4) Inbound Orders flow');

  const inboundCreateRes = await post('/inbound-orders', {
    clientId,
    warehouseId: warehouse.id,
    orderNumber: 'INB-TEST-001',
    currentStage: 'RECEIVING',
  });
  console.log('   POST /inbound-orders ->', inboundCreateRes.status);
  if (inboundCreateRes.status !== 201 && inboundCreateRes.status !== 200) {
    console.log('   ❌ Failed to create inbound order:', inboundCreateRes.body);
  }
  const inboundOrder = inboundCreateRes.body;

  let inboundItem;
  if (inboundOrder && inboundOrder.id) {
    const addItemRes = await post(`/inbound-orders/${inboundOrder.id}/items`, {
      productId: product.id,
      qtyOrdered: 10,
      uomId: uomEA.id,
    });
    console.log(
      '   POST /inbound-orders/:id/items ->',
      addItemRes.status,
    );
    if (addItemRes.status === 201 || addItemRes.status === 200) {
      inboundItem = addItemRes.body;
    } else {
      console.log('   ❌ Failed to add inbound item:', addItemRes.body);
    }
  }

  if (inboundOrder && inboundItem) {
    const receiveRes = await post(`/inbound-orders/${inboundOrder.id}/receive`, {
      itemId: inboundItem.id,
      batches: [
        {
          qtyReceived: 10,
          locationId: location ? location.id : undefined,
        },
      ],
    });
    console.log(
      '   POST /inbound-orders/:id/receive ->',
      receiveRes.status,
    );
    if (
      receiveRes.status !== 201 &&
      receiveRes.status !== 200 &&
      receiveRes.status !== 204
    ) {
      console.log('   ❌ Failed to receive inbound order:', receiveRes.body);
    }
  }
  console.log();

  // ---------------------------------------------------------------------------
  // 5) Outbound order + reservation skeleton (no pick/ship here, that is tested separately)
  // ---------------------------------------------------------------------------
  console.log('5) Outbound Orders + basic reservation');

  const outboundCreateRes = await post('/outbound-orders', {
    clientId,
    warehouseId: warehouse.id,
    orderNumber: 'OUT-TEST-001',
    currentStage: 'ALLOCATING',
  });
  console.log('   POST /outbound-orders ->', outboundCreateRes.status);
  const outboundOrder = outboundCreateRes.body;

  let outboundItem;
  if (outboundOrder && outboundOrder.id) {
    const addOutboundItemRes = await post(
      `/outbound-orders/${outboundOrder.id}/items`,
      {
        productId: product.id,
        qtyOrdered: 5,
        uomId: uomEA.id,
      },
    );
    console.log(
      '   POST /outbound-orders/:id/items ->',
      addOutboundItemRes.status,
    );
    if (addOutboundItemRes.status === 201 || addOutboundItemRes.status === 200) {
      outboundItem = addOutboundItemRes.body;
    } else {
      console.log('   ❌ Failed to add outbound item:', addOutboundItemRes.body);
    }
  }

  if (outboundOrder && outboundItem) {
    const reservationRes = await post(
      `/outbound-orders/${outboundOrder.id}/reservations`,
      {
        outboundOrderId: outboundOrder.id,
        allocations: [
          {
            outboundOrderItemId: outboundItem.id,
            productId: product.id,
            reservedQty: 5,
            // batchId/locationId optional; reservation service checks current_stock
          },
        ],
      },
    );
    console.log(
      '   POST /outbound-orders/:id/reservations ->',
      reservationRes.status,
    );
    if (
      reservationRes.status !== 201 &&
      reservationRes.status !== 200 &&
      reservationRes.status !== 204
    ) {
      console.log(
        '   ❌ Failed to create stock reservation:',
        reservationRes.body,
      );
    }
  }
  console.log();

  // ---------------------------------------------------------------------------
  // 6) Adjustments: create only (apply requires approvals)
  // ---------------------------------------------------------------------------
  console.log('6) Adjustments');

  const adjustmentRes = await post('/adjustments', {
    clientId,
    warehouseId: warehouse.id,
    productId: product.id,
    qtyChange: 1, // small positive adjustment
    reason: 'Test adjustment via script',
  });
  console.log('   POST /adjustments ->', adjustmentRes.status);
  if (adjustmentRes.status !== 201 && adjustmentRes.status !== 200) {
    console.log('   ❌ Failed to create adjustment:', adjustmentRes.body);
  }

  const adjustmentsList = await get('/adjustments');
  console.log('   GET /adjustments ->', adjustmentsList.status);
  if (adjustmentsList.status === 200) {
    console.log(
      '   Count:',
      Array.isArray(adjustmentsList.body) ? adjustmentsList.body.length : 'n/a',
    );
  }
  console.log();

  // ---------------------------------------------------------------------------
  // 7) Return Orders: create + process (RESTOCK)
  // ---------------------------------------------------------------------------
  console.log('7) Return Orders');

  if (outboundOrder && outboundItem) {
    const returnCreateRes = await post('/return-orders', {
      outboundOrderId: outboundOrder.id,
      returnNumber: 'RET-TEST-001',
      productId: product.id,
      qty: 2,
      // disposition defaults to RESTOCK
    });
    console.log('   POST /return-orders ->', returnCreateRes.status);
    const returnOrder = returnCreateRes.body;

    if (returnOrder && returnOrder.id) {
      const processRes = await post(
        `/return-orders/${returnOrder.id}/process`,
        {},
      );
      console.log(
        '   POST /return-orders/:id/process ->',
        processRes.status,
      );
      if (
        processRes.status !== 201 &&
        processRes.status !== 200 &&
        processRes.status !== 204
      ) {
        console.log('   ❌ Failed to process return order:', processRes.body);
      }
    }

    const retList = await get('/return-orders');
    console.log('   GET /return-orders ->', retList.status);
    if (retList.status === 200) {
      console.log(
        '   Count:',
        Array.isArray(retList.body) ? retList.body.length : 'n/a',
      );
    }
  } else {
    console.log(
      '   ⚠️ Skipping return-orders flow because outbound order/item was not created.',
    );
  }
  console.log();

  console.log('✅ Full endpoint test suite completed.');
}

run().catch((err) => {
  console.error('❌ Error in test-all-endpoints script:', err);
  process.exit(1);
});



